(800, 'ABC RADIOGRAFIA DE TORAX RAYOSPEDIA', 'Dr. Lorenz Rodriguez', 2020, 'S.D.', 'https://drive.google.com/file/d/157ItAJD7a_zy0Xi16qRLcRRD79FJuVsE/view?usp=sharing', 'https://m.media-amazon.com/images/I/51Ef0WSsxcL._UF1000,1000_QL80_.jpg', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(801, 'Felson. Principios de Radiología torácica', 'Lawrence R. Goodman', 2009, 'Hablando con los estudiantes sobre la segunda edición de Felson. Principios de\n\nRadiología torácica, descubrí que casi todos querían más casos problema y más to-\nmografía computerizada. Aún así querían que el texto siguiese siendo corto y manejable.', 'https://drive.google.com/file/d/1zbYRaRrAyqwH-zX0VXYOhwjLRgtFvUhT/view?usp=sharing', 'https://3.bp.blogspot.com/-cgCKm-CdKv8/U5d93RwiwWI/AAAAAAAAFq0/jfVhELMAHAw/s1600/Felson+Principios+de+Radiologia+Tor%C3%A1cica+Un+texto+Programado+-+Lawrence+R.+Goodman.jpg', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(802, 'MANUAL DE RADIOLOGIA', 'Prof. Edwin Saldaña Ambulódegui', 2020, 'S.D.', 'https://drive.google.com/file/d/1i0zRc2ZFwTiPjofNVqs2I3n3wVmtHdq_/view?usp=sharing', 'https://imgv2-2-f.scribdassets.com/img/document/370921553/original/bd30cef12a/1?v=1', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(803, 'Radiologia basica. Aspectos fundamentales 3a Edicion RADIOLOGIA CONVENCIONAL FLUOROSCOPIA MEDICINA NUCLEAR', 'S.A.', 2020, 'S.D.', 'https://drive.google.com/file/d/1NWF1wA0-TyyfFu7MUy4il_vYzS3nSkci/view?usp=sharing', 'https://4.bp.blogspot.com/--K9C2qBDqf8/X0_jcWzYZQI/AAAAAAAAc_4/uidhLtQE42kuqavMMfb5U3eCwXlq-AUOgCLcBGAsYHQ/s1600/Radiologia%2Bbasica.Aspectos%2Bfundamentales%2BHerring%2B3a%2BEdicion.jpg', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(804, 'manual basico de imagenologia', 'MD. Fátima Yadira Rivera Rasury', 2021, 'S.D.', 'https://drive.google.com/file/d/19Olb7qvcACiL4FkcYDstfjzdbE6r3b1T/view?usp=sharing', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTN0PlId59rRvg49IpCU1VXqdLjtY1UDsV8wg&s', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(805, 'Radiología básica', 'Michael Y. M. Chen Thomas L. Pope, Jr. David J. Ott', 2004, 'La medicina es una ciencia sometida a un cambio constante. A\nmedida que la investigación y la experiencia clínica amplían\n\nnuestros conocimientos, son necesarios cambios en los trata-\nmientos y la farmacoterapia.', 'https://drive.google.com/file/d/16DfVaeLxrJk1EXYT6b_Atod0F-YTSmF-/view?usp=sharing', 'https://www.ingebook.com/ib/pimg/Ingebook/00100_0000005197_5621.JPG', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(806, 'Anatomia Radiologica Moller 2da Ed.', 'S.A.', 2020, 's.d.', 'https://drive.google.com/file/d/1KZq98kU_nexFzZQQbmFhDZf1dEsaPB_J/view?usp=sharing', 'https://imgv2-1-f.scribdassets.com/img/document/469165913/original/4c41b484b2/1?v=1', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(807, 'DIAGNOSTICO POR IMAGENES RADIOLOGÍA DE TORAX', 'S.A.', 2020, 'La radiografía de tórax es la exploración básica imagenológica y tiene un gran rendimiento en\npacientes con sospecha de patología torácica, ya que la mayor parte de estas enfermedades\ntienen expresión radiográfica.', 'https://drive.google.com/file/d/1_1uo2S4URszeE8Ga1DnR3hbPtq17kvwX/view?usp=sharing', 'https://diagnosticar-ips.com/wp-content/uploads/2022/09/female-chest-x-ray.jpg', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(808, 'Proyecciones radiológicas con correlación anatómica', 'Kenneth L. Bontrager, MA John P. Lampignano, MEd, RT(R)(CT)', 2010, 'Esta edición es, de nuevo, la culminación del esfuerzo de un equipo\nde numerosos colaboradores y revisores. Aprecio cada vez más la\nventaja que tienen las nuevas ediciones de una misma obra al brindar\nla oportunidad de corregir, añadir y mejorar cada edición previa.', 'https://drive.google.com/file/d/1La0vBX4l6sVB-QDerSw55Hao-5xx1pUZ/view?usp=sharing', 'https://image.cdn0.buscalibre.com/2970935.__RS360x360__.jpg', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(809, 'RADIOGRAFIA DE ABDOMEN RAYOSPEDIA', 'Dr. Lorenz RodrÌguez', 2020, 'La radiografÌa de abdomen, no solo sirve para descartar neumoperitoneo o para\nbuscar niveles hidroaÈreos. Una radiografÌa simple de abdomen puede\naportarte informaciÛn valiosa para el diagnÛstico del paciente, claro, si sabes\ncÛmo interpretarla.', 'https://drive.google.com/file/d/1B0JTCJBEQMFaI7eN8QMKOrMO9DmsNsLQ/view?usp=sharing', 'https://m.media-amazon.com/images/I/51t6y0f7TAL._UF1000,1000_QL80_.jpg', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
(810, 'Manual Tecnico de Saneamiento Basico', 'S.A.', 2020, 's.d.', 'https://drive.google.com/file/d/12Ag5iX9kfTKcFsBkClE6SkAItOPEBaYH/view?usp=sharing', 'https://sihita.org/wp-content/uploads/2022/05/Captura-63.jpg', '2026-03-04 15:10:08', '2026-03-04 15:10:10'),
